@tailwind base;
@tailwind components;
@tailwind utilities;

/* =========================================
   BASE SETTINGS
   ========================================= */
html {
  scroll-behavior: smooth;
  -webkit-tap-highlight-color: transparent;
  width: 100%;
  overflow-x: hidden;
  background-color: #081437;
  scrollbar-gutter: stable; /* Crucial para o fix da tremida lateral */
}

body {
  @apply font-sans text-brand-text bg-brand-blue-dark antialiased;
  width: 100%;
  overflow-x: hidden;
  position: relative;
  min-height: 100vh;
}

/* =========================================
   GLOBAL ANIMATIONS
   ========================================= */

/* Page Transition Fade */
@keyframes page-fade-in {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-page-in {
  animation: page-fade-in 0.4s cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* Shimmer / Skeleton Loading */
@keyframes shimmer {
  0% { background-position: -1000px 0; }
  100% { background-position: 1000px 0; }
}

.animate-shimmer {
  animation: shimmer 2s infinite linear;
  background: linear-gradient(to right, #111d40 8%, #1a2954 18%, #111d40 33%);
  background-size: 1000px 104px;
}

/* Slide In Up */
@keyframes slide-in-up {
  from { opacity: 0; transform: translateY(2rem); }
  to { opacity: 1; transform: translateY(0); }
}

.animate-slide-in {
  opacity: 0;
  animation: slide-in-up 0.7s cubic-bezier(0.25, 0.46, 0.45, 0.94) forwards;
}

/* Fade In Scale (Modal) */
@keyframes fade-in-scale {
  from { opacity: 0; transform: scale(0.95); }
  to { opacity: 1; transform: scale(1); }
}

.animate-fade-in-scale {
  animation: fade-in-scale 0.2s ease-out forwards;
}

/* =========================================
   CUSTOM SCROLLBAR
   ========================================= */
::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: #050c21;
}

::-webkit-scrollbar-thumb {
  background: #212c4b;
  border-radius: 4px;
  transition: background-color 0.3s;
}

::-webkit-scrollbar-thumb:hover {
  background: #C2410C; /* Brand Orange */
}

/* =========================================
   UTILITIES & COMPONENTS
   ========================================= */

/* Glassmorphism */
.glass {
  @apply bg-white/90 backdrop-blur-md border-b border-white/20;
}

.glass-dark {
  @apply bg-brand-blue-dark/95 backdrop-blur-md border-b border-white/10;
}

/* Form Inputs */
@layer components {
  .input-label-lg {
    @apply block text-xs text-slate-300 uppercase font-extrabold mb-3 tracking-wide;
  }

  .input-field-lg {
    @apply w-full bg-slate-800 border border-white/10 rounded-xl p-4 text-white outline-none focus:border-brand-orange focus:ring-1 focus:ring-brand-orange transition-all placeholder-gray-500;
  }

  .input-label {
    @apply block text-[10px] text-gray-400 uppercase font-bold mb-1.5 tracking-wider;
  }

  .input-field {
    @apply w-full bg-[#1e293b] border border-white/10 rounded-lg py-3 px-3 text-white text-sm outline-none focus:border-brand-orange transition-colors placeholder-gray-600;
  }

  .btn-primary {
    @apply bg-brand-orange text-white font-bold py-3 px-8 rounded-lg hover:bg-brand-orange-dark transition-all duration-300 shadow-lg hover:shadow-brand-orange/20 active:scale-95 uppercase tracking-wider text-sm;
  }
}

import React from 'react';

/**
 * LoadingSpinner otimizado para evitar flashes brancos e layout shifts agressivos.
 * Utiliza as cores escuras do tema Aços Vital.
 */
const LoadingSpinner: React.FC = () => {
  return (
    <div className="w-full bg-brand-blue-dark min-h-[60vh] flex flex-col" aria-live="polite" aria-busy="true" aria-label="Carregando conteúdo...">
      {/* Hero Skeleton Otimizado */}
      <div className="bg-[#0b1635] h-[45vh] min-h-[350px] w-full animate-shimmer relative overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-b from-transparent to-brand-blue-dark/50"></div>
      </div>

      {/* Conteúdo Skeleton */}
      <div className="container mx-auto px-6 sm:px-12 lg:px-24 py-16 flex-grow">
        <div className="max-w-4xl mx-auto space-y-8">
          <div className="h-12 w-1/2 rounded-lg bg-[#0b1635] animate-shimmer"></div>

          <div className="space-y-4">
            <div className="h-4 w-full rounded bg-[#0b1635] animate-shimmer"></div>
            <div className="h-4 w-full rounded bg-[#0b1635] animate-shimmer"></div>
            <div className="h-4 w-3/4 rounded bg-[#0b1635] animate-shimmer"></div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 pt-8">
             <div className="h-48 rounded-2xl bg-[#0b1635] animate-shimmer"></div>
             <div className="h-48 rounded-2xl bg-[#0b1635] animate-shimmer"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default LoadingSpinner;

import React, { useEffect } from 'react';
import { Routes, Route, Navigate, useLocation } from 'react-router-dom';
import Header from './components/layout/Header';
import Footer from './components/layout/Footer';
import LoadingSpinner from './components/common/LoadingSpinner';
import CookieBanner from './components/common/CookieBanner';
import FloatingWhatsapp from './components/common/FloatingWhatsapp';

// Componente utilitário para resetar o scroll ao topo em cada mudança de rota
const ScrollToTop = () => {
    const { pathname } = useLocation();
    useEffect(() => {
        window.scrollTo({ top: 0, left: 0, behavior: 'instant' });
    }, [pathname]);
    return null;
};

// --- 1. DEFINIÇÃO DAS PÁGINAS (LAZY LOADING) ---
const HomePage = React.lazy(() => import('./pages/HomePage'));
const AboutPage = React.lazy(() => import('./pages/AboutPage'));
const ProductsPage = React.lazy(() => import('./pages/ProductsPage'));
const CatalogPage = React.lazy(() => import('./pages/CatalogPage'));
const CertificationsPage = React.lazy(() => import('./pages/CertificationsPage'));
const ContactPage = React.lazy(() => import('./pages/ContactPage'));
const NotFoundPage = React.lazy(() => import('./pages/NotFoundPage'));
const TablesPage = React.lazy(() => import('./pages/TablesPage'));
const CalculatorPage = React.lazy(() => import('./pages/CalculatorPage'));
const PrivacyPolicyPage = React.lazy(() => import('./pages/PrivacyPolicyPage'));

// Subpages
const FlangeProductPage = React.lazy(() => import('./subpages/FlangeProductPage'));
const TubosProductPage = React.lazy(() => import('./subpages/TubosProductPage'));
const ConexoesProductPage = React.lazy(() => import('./subpages/ConexoesProductPage'));
const ValvulasProductPage = React.lazy(() => import('./subpages/ValvulasProductPage'));
const PerfisLaminadosProductPage = React.lazy(() => import('./subpages/PerfisLaminadosProductPage'));
const ChapasProductPage = React.lazy(() => import('./subpages/ChapasProductPage'));
const GradesPisoProductPage = React.lazy(() => import('./subpages/GradesPisoProductPage'));
const TelhasTrapezoidaisProductPage = React.lazy(() => import('./subpages/TelhasTrapezoidaisProductPage'));
const CivilProductPage = React.lazy(() => import('./subpages/CivilProductPage'));
const CaldeirariaProductPage = React.lazy(() => import('./subpages/CaldeirariaProductPage'));
const OxicorteProductPage = React.lazy(() => import('./subpages/OxicorteProductPage'));
const EletrodutosProductPage = React.lazy(() => import('./subpages/EletrodutosProductPage'));
const GroovedProductPage = React.lazy(() => import('./subpages/GroovedProductPage'));
const TanqueCombustivelProductPage = React.lazy(() => import('./subpages/TanqueCombustivelProductPage'));

const App: React.FC = () => {
    const location = useLocation();

    return (
        <div className="bg-brand-blue-dark font-sans text-gray-800 flex flex-col min-h-screen w-full overflow-x-hidden relative">
            <ScrollToTop />
            <Header />

            <main className="flex-grow w-full flex flex-col min-h-[80vh]">
                <React.Suspense fallback={<LoadingSpinner />}>
                    <div key={location.pathname} className="animate-page-in">
                        <Routes location={location}>
                            {/* Rotas Principais */}
                            <Route path="/" element={<HomePage />} />
                            <Route path="/home" element={<Navigate to="/" replace />} />
                            <Route path="/about" element={<AboutPage />} />
                            <Route path="/products" element={<ProductsPage />} />
                            <Route path="/catalog" element={<CatalogPage />} />
                            <Route path="/tables" element={<TablesPage />} />
                            <Route path="/calculator" element={<CalculatorPage />} />
                            <Route path="/certifications" element={<CertificationsPage />} />
                            <Route path="/contact" element={<ContactPage />} />
                            <Route path="/privacy" element={<PrivacyPolicyPage />} />

                            {/* Rotas de Produtos */}
                            <Route path="/products/flanges" element={<FlangeProductPage />} />
                            <Route path="/products/tubos" element={<TubosProductPage />} />
                            <Route path="/products/conexoes" element={<ConexoesProductPage />} />
                            <Route path="/products/valvulas" element={<ValvulasProductPage />} />
                            <Route path="/products/perfis" element={<PerfisLaminadosProductPage />} />
                            <Route path="/products/chapas" element={<ChapasProductPage />} />
                            <Route path="/products/grades" element={<GradesPisoProductPage />} />
                            <Route path="/products/telhas" element={<TelhasTrapezoidaisProductPage />} />
                            <Route path="/products/civil" element={<CivilProductPage />} />
                            <Route path="/products/caldeiraria" element={<CaldeirariaProductPage />} />
                            <Route path="/products/oxicorte" element={<OxicorteProductPage />} />
                            <Route path="/products/eletrodutos" element={<EletrodutosProductPage />} />
                            <Route path="/products/grooved" element={<GroovedProductPage />} />
                            <Route path="/products/tanques" element={<TanqueCombustivelProductPage />} />

                            {/* Rota 404 */}
                            <Route path="*" element={<NotFoundPage />} />
                        </Routes>
                    </div>
                </React.Suspense>
            </main>

            <Footer />
            <FloatingWhatsapp />
            <CookieBanner />
        </div>
    );
};

export default App;

