const SOCIAL_ICONS: Record<string, any> = {
    facebook: Facebook,
    instagram: Instagram,
    linkedin: Linkedin,
};

const Header: React.FC = () => {
    const { t } = useTranslation();
    const currentRoute = useRouter();
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [isSearchOpen, setIsSearchOpen] = useState(false);
    const [isScrolled, setIsScrolled] = useState(false);

    // Mobile Menu States
    const [activeProductGroup, setActiveProductGroup] = useState<string | null>(null);
    const [isProductsExpanded, setIsProductsExpanded] = useState(false);

    const MOBILE_PRODUCT_GROUPS = [
        {
            id: 'tubular',
            label: t('header.mobileGroups.tubular'),
            icon: <Layers size={20} />,
            items: ['tubes', 'conduits', 'grooved']
        },
        {
            id: 'connections',
            label: t('header.mobileGroups.connections'),
            icon: <Settings size={20} />,
            items: ['flanges', 'fittings', 'valves']
        },
        {
            id: 'structural',
            label: t('header.mobileGroups.structural'),
            icon: <Box size={20} />,
            items: ['profiles', 'plates', 'gratings', 'tiles']
        },
        {
            id: 'industrial',
            label: t('header.mobileGroups.industrial'),
            icon: <Factory size={20} />,
            items: ['civil', 'boilermaking', 'cutting', 'tanks']
        }
    ];

    const closeMobileMenu = () => {
        setIsMobileMenuOpen(false);
        setActiveProductGroup(null);
        setIsProductsExpanded(false);
    };

    const toggleMobileMenu = () => setIsMobileMenuOpen(prev => !prev);

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 20);
        };
        window.addEventListener('scroll', handleScroll);

        const handleKeyDown = (e: KeyboardEvent) => {
            if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
                e.preventDefault();
                setIsSearchOpen(true);
            }
            if (e.key === 'Escape' && isMobileMenuOpen) {
                closeMobileMenu();
            }
        };
        window.addEventListener('keydown', handleKeyDown);
        return () => {
            window.removeEventListener('scroll', handleScroll);
            window.removeEventListener('keydown', handleKeyDown);
        };
    }, [isMobileMenuOpen]);

    useEffect(() => {
        if (isMobileMenuOpen) {
